import os
from pathlib import Path

def delete_user_file(filename, base_directory='uploads'):
    base_path = Path(base_directory).resolve()
    
    if not base_path.exists():
        raise ValueError(f"Base directory '{base_directory}' does not exist")
    
    if not base_path.is_dir():
        raise ValueError(f"Base directory '{base_directory}' is not a directory")
    
    file_path = (base_path / filename).resolve()
    
    try:
        file_path.relative_to(base_path)
    except ValueError:
        raise ValueError(f"Invalid file path: attempting to access outside base directory")
    
    if not file_path.exists():
        raise FileNotFoundError(f"File '{filename}' not found")
    
    if not file_path.is_file():
        raise ValueError(f"Path '{filename}' is not a file")
    
    os.remove(file_path)
    return True